22: // The _MAX values are a bit wonky here because we are overloading the first
23: // byte of the auth payload to identify both the type of authentication to be
24: // used *and* the encoding version for the authenticator.  So, we define a
25: // range.
26: enum {
27:   AUTH_MODE_NONE = 0,
28:   AUTH_MODE_AUTHORIZER = 1,
29:   AUTH_MODE_AUTHORIZER_MAX = 9,
30:   AUTH_MODE_MON = 10,
31:   AUTH_MODE_MON_MAX = 19,
32: };
