35: struct EntityAuth {
36:   CryptoKey key;
37:   std::map<std::string, ceph::buffer::list> caps;
38:   CryptoKey pending_key; ///< new but uncommitted key
39: 
40:   void encode(ceph::buffer::list& bl) const {
41:     __u8 struct_v = 3;
42:     using ceph::encode;
43:     encode(struct_v, bl);
44:     encode((uint64_t)CEPH_AUTH_UID_DEFAULT, bl);
45:     encode(key, bl);
46:     encode(caps, bl);
47:     encode(pending_key, bl);
48:   }
49:   void decode(ceph::buffer::list::const_iterator& bl) {
50:     using ceph::decode;
51:     __u8 struct_v;
52:     decode(struct_v, bl);
53:     if (struct_v >= 2) {
54:       uint64_t old_auid;
55:       decode(old_auid, bl);
56:     }
57:     decode(key, bl);
58:     decode(caps, bl);
59:     if (struct_v >= 3) {
60:       decode(pending_key, bl);
61:     }
62:   }
63:   void dump(ceph::Formatter *f) const {
64:     f->dump_object("key", key);
65:     encode_json("caps", caps, f);
66:     f->dump_object("pending_key", pending_key);
67:   }
68:   static void generate_test_instances(std::list<EntityAuth*>& ls) {
69:     ls.push_back(new EntityAuth);
70:   }
71: };
72: WRITE_CLASS_ENCODER(EntityAuth)
73: 
74: inline std::ostream& operator<<(std::ostream& out, const EntityAuth& a)
75: {
76:   out << "auth(key=" << a.key;
77:   if (!a.pending_key.empty()) {
78:     out << " pending_key=" << a.pending_key;
79:   }
80:   out << ")";
81:   return out;
82: }
