84: struct AuthCapsInfo {
85:   bool allow_all;
86:   ceph::buffer::list caps;
87: 
88:   AuthCapsInfo() : allow_all(false) {}
89: 
90:   void encode(ceph::buffer::list& bl) const {
91:     using ceph::encode;
92:     __u8 struct_v = 1;
93:     encode(struct_v, bl);
94:     __u8 a = (__u8)allow_all;
95:     encode(a, bl);
96:     encode(caps, bl);
97:   }
98:   void decode(ceph::buffer::list::const_iterator& bl) {
99:     using ceph::decode;
100:     __u8 struct_v;
101:     decode(struct_v, bl);
102:     __u8 a;
103:     decode(a, bl);
104:     allow_all = (bool)a;
105:     decode(caps, bl);
106:   }
107:   void dump(ceph::Formatter *f) const {
108:     f->dump_bool("allow_all", allow_all);
109:     encode_json("caps", caps, f);
110:     f->dump_unsigned("caps_len", caps.length());
111:   }
112:   static void generate_test_instances(std::list<AuthCapsInfo*>& ls) {
113:     ls.push_back(new AuthCapsInfo);
114:     ls.push_back(new AuthCapsInfo);
115:     ls.back()->allow_all = true;
116:     ls.push_back(new AuthCapsInfo);
117:     ls.back()->caps.append("foo");
118:     ls.back()->caps.append("bar");
119:   }
120: };
121: WRITE_CLASS_ENCODER(AuthCapsInfo)
