123: /*
124:  * The ticket (if properly validated) authorizes the principal use
125:  * services as described by 'caps' during the specified validity
126:  * period.
127:  */
128: struct AuthTicket {
129:   EntityName name;
130:   uint64_t global_id; /* global instance id */
131:   utime_t created, renew_after, expires;
132:   AuthCapsInfo caps;
133:   __u32 flags;
134: 
135:   AuthTicket() : global_id(0), flags(0){}
136: 
137:   void init_timestamps(utime_t now, double ttl) {
138:     created = now;
139:     expires = now;
140:     expires += ttl;
141:     renew_after = now;
142:     renew_after += ttl / 2.0;
143:   }
144: 
145:   void encode(ceph::buffer::list& bl) const {
146:     using ceph::encode;
147:     __u8 struct_v = 2;
148:     encode(struct_v, bl);
149:     encode(name, bl);
150:     encode(global_id, bl);
151:     encode((uint64_t)CEPH_AUTH_UID_DEFAULT, bl);
152:     encode(created, bl);
153:     encode(expires, bl);
154:     encode(caps, bl);
155:     encode(flags, bl);
156:   }
157:   void decode(ceph::buffer::list::const_iterator& bl) {
158:     using ceph::decode;
159:     __u8 struct_v;
160:     decode(struct_v, bl);
161:     decode(name, bl);
162:     decode(global_id, bl);
163:     if (struct_v >= 2) {
164:       uint64_t old_auid;
165:       decode(old_auid, bl);
166:     }
167:     decode(created, bl);
168:     decode(expires, bl);
169:     decode(caps, bl);
170:     decode(flags, bl);
171:   }
172:   void dump(ceph::Formatter *f) const {
173:     f->dump_object("name", name);
174:     f->dump_unsigned("global_id", global_id);
175:     f->dump_stream("created") << created;
176:     f->dump_stream("renew_after") << renew_after;
177:     f->dump_stream("expires") << expires;
178:     f->dump_object("caps", caps);
179:     f->dump_unsigned("flags", flags);
180:   }
181:   static void generate_test_instances(std::list<AuthTicket*>& ls) {
182:     ls.push_back(new AuthTicket);
183:     ls.push_back(new AuthTicket);
184:     ls.back()->name.set_id("client.123");
185:     ls.back()->global_id = 123;
186:     ls.back()->init_timestamps(utime_t(123, 456), 7);
187:     ls.back()->caps.caps.append("foo");
188:     ls.back()->caps.caps.append("bar");
189:     ls.back()->flags = 0x12345678;
190:   }
191: };
