252: /*
253:  * Key management
254:  */ 
255: #define KEY_ROTATE_NUM 3   /* prev, current, next */
256: 
257: struct ExpiringCryptoKey {
258:   CryptoKey key;
259:   utime_t expiration;
260: 
261:   void encode(ceph::buffer::list& bl) const {
262:     using ceph::encode;
263:     __u8 struct_v = 1;
264:     encode(struct_v, bl);
265:     encode(key, bl);
266:     encode(expiration, bl);
267:   }
268:   void decode(ceph::buffer::list::const_iterator& bl) {
269:     using ceph::decode;
270:     __u8 struct_v;
271:     decode(struct_v, bl);
272:     decode(key, bl);
273:     decode(expiration, bl);
274:   }
275:   void dump(ceph::Formatter *f) const {
276:     f->dump_object("key", key);
277:     f->dump_stream("expiration") << expiration;
278:   }
279:   static void generate_test_instances(std::list<ExpiringCryptoKey*>& ls) {
280:     ls.push_back(new ExpiringCryptoKey);
281:     ls.push_back(new ExpiringCryptoKey);
282:     ls.back()->key.set_secret(
283:       CEPH_CRYPTO_AES, bufferptr("1234567890123456", 16), utime_t(123, 456));
284:   }
285: };
286: WRITE_CLASS_ENCODER(ExpiringCryptoKey)
287: 
288: inline std::ostream& operator<<(std::ostream& out, const ExpiringCryptoKey& c)
289: {
290:   return out << c.key << " expires " << c.expiration;
291: }
292: 
293: struct RotatingSecrets {
294:   std::map<uint64_t, ExpiringCryptoKey> secrets;
295:   version_t max_ver;
296: 
297:   RotatingSecrets() : max_ver(0) {}
298: 
299:   void encode(ceph::buffer::list& bl) const {
300:     using ceph::encode;
301:     __u8 struct_v = 1;
302:     encode(struct_v, bl);
303:     encode(secrets, bl);
304:     encode(max_ver, bl);
305:   }
306:   void decode(ceph::buffer::list::const_iterator& bl) {
307:     using ceph::decode;
308:     __u8 struct_v;
309:     decode(struct_v, bl);
310:     decode(secrets, bl);
311:     decode(max_ver, bl);
312:   }
313:   
314:   uint64_t add(ExpiringCryptoKey& key) {
315:     secrets[++max_ver] = key;
316:     while (secrets.size() > KEY_ROTATE_NUM)
317:       secrets.erase(secrets.begin());
318:     return max_ver;
319:   }
320:   
321:   bool need_new_secrets() const {
322:     return secrets.size() < KEY_ROTATE_NUM;
323:   }
324:   bool need_new_secrets(const utime_t& now) const {
325:     return secrets.size() < KEY_ROTATE_NUM || current().expiration <= now;
326:   }
327: 
328:   ExpiringCryptoKey& previous() {
329:     return secrets.begin()->second;
330:   }
331:   ExpiringCryptoKey& current() {
332:     auto p = secrets.begin();
333:     ++p;
334:     return p->second;
335:   }
336:   const ExpiringCryptoKey& current() const {
337:     auto p = secrets.begin();
338:     ++p;
339:     return p->second;
340:   }
341:   ExpiringCryptoKey& next() {
342:     return secrets.rbegin()->second;
343:   }
344:   bool empty() {
345:     return secrets.empty();
346:   }
347: 
348:   void dump();
349:   void dump(ceph::Formatter *f) const {
350:     encode_json("secrets", secrets, f);
351:   }
352:   static void generate_test_instances(std::list<RotatingSecrets*>& ls) {
353:     ls.push_back(new RotatingSecrets);
354:     ls.push_back(new RotatingSecrets);
355:     auto eck = new ExpiringCryptoKey;
356:     ls.back()->add(*eck);
357:   }
358: };
359: WRITE_CLASS_ENCODER(RotatingSecrets)
