153: // client -> server response to challenge
154: struct CephXAuthenticate {
155:   uint64_t client_challenge;
156:   uint64_t key;
157:   CephXTicketBlob old_ticket;
158:   uint32_t other_keys = 0;  // replaces CephXServiceTicketRequest
159: 
160:   bool old_ticket_may_be_omitted;
161: 
162:   void encode(ceph::buffer::list& bl) const {
163:     using ceph::encode;
164:     __u8 struct_v = 3;
165:     encode(struct_v, bl);
166:     encode(client_challenge, bl);
167:     encode(key, bl);
168:     encode(old_ticket, bl);
169:     encode(other_keys, bl);
170:   }
171:   void decode(ceph::buffer::list::const_iterator& bl) {
172:     using ceph::decode;
173:     __u8 struct_v;
174:     decode(struct_v, bl);
175:     decode(client_challenge, bl);
176:     decode(key, bl);
177:     decode(old_ticket, bl);
178:     if (struct_v >= 2) {
179:       decode(other_keys, bl);
180:     }
181: 
182:     // v2 and v3 encodings are the same, but:
183:     // - some clients that send v1 or v2 don't populate old_ticket
184:     //   on reconnects (but do on renewals)
185:     // - any client that sends v3 or later is expected to populate
186:     //   old_ticket both on reconnects and renewals
187:     old_ticket_may_be_omitted = struct_v < 3;
188:   }
189:   void dump(ceph::Formatter *f) const {
190:     f->dump_unsigned("client_challenge", client_challenge);
191:     f->dump_unsigned("key", key);
192:     f->open_object_section("old_ticket");
193:     old_ticket.dump(f);
194:     f->close_section();
195:     f->dump_unsigned("other_keys", other_keys);
196:   }
197:   static void generate_test_instances(std::list<CephXAuthenticate*>& ls) {
198:     ls.push_back(new CephXAuthenticate);
199:     ls.back()->client_challenge = 0;
200:     ls.back()->key = 0;
201:     ls.push_back(new CephXAuthenticate);
202:     ls.back()->client_challenge = 1;
203:     ls.back()->key = 2;
204:     ls.back()->old_ticket.secret_id = 3;
205:     ls.back()->old_ticket.blob.append(std::string_view("this is a blob"));
206:     ls.back()->other_keys = 4;
207:   }
208: };
209: WRITE_CLASS_ENCODER(CephXAuthenticate)
