23: struct KeyServerData {
24:   version_t version{0};
25: 
26:   /* for each entity */
27:   std::map<EntityName, EntityAuth> secrets;
28:   KeyRing *extra_secrets = nullptr;
29: 
30:   /* for each service type */
31:   version_t rotating_ver{0};
32:   std::map<uint32_t, RotatingSecrets> rotating_secrets;
33:   KeyServerData() {}
34: 
35:   explicit KeyServerData(KeyRing *extra)
36:     : version(0),
37:       extra_secrets(extra),
38:       rotating_ver(0) {}
39: 
40:   void encode(ceph::buffer::list& bl) const {
41:      __u8 struct_v = 1;
42:     using ceph::encode;
43:     encode(struct_v, bl);
44:     encode(version, bl);
45:     encode(rotating_ver, bl);
46:     encode(secrets, bl);
47:     encode(rotating_secrets, bl);
48:   }
49:   void decode(ceph::buffer::list::const_iterator& bl) {
50:     using ceph::decode;
51:     __u8 struct_v;
52:     decode(struct_v, bl);
53:     decode(version, bl);
54:     decode(rotating_ver, bl);
55:     decode(secrets, bl);
56:     decode(rotating_secrets, bl);
57:   }
58: 
59:   void encode_rotating(ceph::buffer::list& bl) const {
60:     using ceph::encode;
61:      __u8 struct_v = 1;
62:     encode(struct_v, bl);
63:     encode(rotating_ver, bl);
