33: class AuthMonitor : public PaxosService {
34: 
35: public:
36:   typedef enum {
37:     CAPS_UPDATE_NOT_REQD, CAPS_UPDATE_REQD, CAPS_PARSING_ERR
38:   } caps_update;
39: 
40:   enum IncType {
41:     GLOBAL_ID,
42:     AUTH_DATA,
43:   };
44:   struct Incremental {
45:     IncType inc_type;
46:     uint64_t max_global_id;
47:     uint32_t auth_type;
48:     ceph::buffer::list auth_data;
49: 
50:     Incremental() : inc_type(GLOBAL_ID), max_global_id(0), auth_type(0) {}
51: 
52:     void encode(ceph::buffer::list& bl, uint64_t features=-1) const {
53:       using ceph::encode;
54:       ENCODE_START(2, 2, bl);
55:       __u32 _type = (__u32)inc_type;
56:       encode(_type, bl);
57:       if (_type == GLOBAL_ID) {
58: 	encode(max_global_id, bl);
59:       } else {
60: 	encode(auth_type, bl);
61: 	encode(auth_data, bl);
62:       }
63:       ENCODE_FINISH(bl);
64:     }
65:     void decode(ceph::buffer::list::const_iterator& bl) {
66:       DECODE_START_LEGACY_COMPAT_LEN(2, 2, 2, bl);
67:       __u32 _type;
68:       decode(_type, bl);
69:       inc_type = (IncType)_type;
70:       ceph_assert(inc_type >= GLOBAL_ID && inc_type <= AUTH_DATA);
71:       if (_type == GLOBAL_ID) {
72: 	decode(max_global_id, bl);
73:       } else {
74: 	decode(auth_type, bl);
75: 	decode(auth_data, bl);
76:       }
77:       DECODE_FINISH(bl);
78:     }
79:     void dump(ceph::Formatter *f) const {
80:       f->dump_int("type", inc_type);
81:       f->dump_int("max_global_id", max_global_id);
82:       f->dump_int("auth_type", auth_type);
83:       f->dump_int("auth_data_len", auth_data.length());
84:     }
85:     static void generate_test_instances(std::list<Incremental*>& ls) {
86:       ls.push_back(new Incremental);
87:       ls.push_back(new Incremental);
88:       ls.back()->inc_type = GLOBAL_ID;
89:       ls.back()->max_global_id = 1234;
90:       ls.push_back(new Incremental);
91:       ls.back()->inc_type = AUTH_DATA;
92:       ls.back()->auth_type = 12;
93:       ls.back()->auth_data.append("foo");
94:     }
95:   };
96: 
97:   struct auth_entity_t {
98:     EntityName name;
99:     EntityAuth auth;
100:   };
