131:   // -- incremental updates --
132:   typedef enum {
133:     AUTH_INC_NOP,
134:     AUTH_INC_ADD,
135:     AUTH_INC_DEL,
136:     AUTH_INC_SET_ROTATING,
137:   } IncrementalOp;
138: 
139:   struct Incremental {
140:     IncrementalOp op;
141:     ceph::buffer::list rotating_bl;  // if SET_ROTATING.  otherwise,
142:     EntityName name;
143:     EntityAuth auth;
144: 
145:     void encode(ceph::buffer::list& bl) const {
146:       using ceph::encode;
147:       __u8 struct_v = 1;
148:       encode(struct_v, bl);
149:      __u32 _op = (__u32)op;
150:       encode(_op, bl);
151:       if (op == AUTH_INC_SET_ROTATING) {
152: 	encode(rotating_bl, bl);
153:       } else {
154: 	encode(name, bl);
155: 	encode(auth, bl);
156:       }
157:     }
158:     void decode(ceph::buffer::list::const_iterator& bl) {
159:       using ceph::decode;
160:       __u8 struct_v;
161:       decode(struct_v, bl);
162:       __u32 _op;
163:       decode(_op, bl);
164:       op = (IncrementalOp)_op;
165:       ceph_assert(op >= AUTH_INC_NOP && op <= AUTH_INC_SET_ROTATING);
166:       if (op == AUTH_INC_SET_ROTATING) {
167: 	decode(rotating_bl, bl);
168:       } else {
169: 	decode(name, bl);
170: 	decode(auth, bl);
171:       }
172:     }
173:     void dump(ceph::Formatter *f) const {
174:       f->dump_unsigned("op", op);
175:       f->dump_object("name", name);
176:       f->dump_object("auth", auth);
177:     }
178:     static void generate_test_instances(std::list<Incremental*>& ls) {
179:       ls.push_back(new Incremental);
180:       ls.back()->op = AUTH_INC_DEL;
181:       ls.push_back(new Incremental);
182:       ls.back()->op = AUTH_INC_ADD;
183:       ls.push_back(new Incremental);
184:       ls.back()->op = AUTH_INC_SET_ROTATING;
185:     }
186:   };
187:   
188:   void apply_incremental(Incremental& inc) {
189:     switch (inc.op) {
190:     case AUTH_INC_ADD:
191:       add_auth(inc.name, inc.auth);
192:       break;
193:       
194:     case AUTH_INC_DEL:
195:       remove_secret(inc.name);
196:       break;
197: 
198:     case AUTH_INC_SET_ROTATING:
199:       decode_rotating(inc.rotating_bl);
200:       break;
201: 
202:     case AUTH_INC_NOP:
203:       break;
204: 
205:     default:
206:       ceph_abort();
207:     }
208:   }
209: 
210: };
